// 날짜 계산: 전일(어제) + 이번 달 + 올해 + 전년 동기
let body = {};
try { body = $('수동 조회').first().json.body || {}; } catch(e) {}
const chatId = String(body.chatId || body.chat_id || '7713811206');

const now = new Date();
const kstOffset = 9 * 60 * 60 * 1000;
const kstNow = new Date(now.getTime() + kstOffset);

const yesterday = new Date(kstNow);
yesterday.setDate(yesterday.getDate() - 1);

const yDate = yesterday.toISOString().slice(0, 10); // 2026-04-09
const yYear = yDate.slice(0, 4);
const yMonth = yDate.slice(0, 7); // 2026-04
const prevYear = String(parseInt(yYear) - 1);
const prevYearMonth = prevYear + yDate.slice(4, 7); // 2025-04

// sheetsRow: 2026-01-01이 2행이므로
const p = yDate.split('-').map(Number);
const target = new Date(Date.UTC(p[0], p[1]-1, p[2]));
const jan1 = new Date(Date.UTC(parseInt(yYear), 0, 1));
const sheetsRow = Math.round((target - jan1) / 86400000) + 2;

// 요일
const dowNames = ['일','월','화','수','목','금','토'];
const dow = dowNames[yesterday.getDay()];
const m = yesterday.getMonth() + 1;
const d = yesterday.getDate();

// 이번 달의 몇 번째 날인지 (누계 일수)
const mtdDays = d;

return [{ json: {
  chatId,
  yDate,
  yYear,
  yMonth,
  prevYear,
  prevYearMonth,
  sheetsRow,
  dow,
  monthNum: m,
  dayNum: d,
  mtdDays,
  label: `${m}/${d}(${dow}) 확정`,
} }];

// 수동 채널(쿠팡/로켓/기타) 파싱 + 자동 채널 값 확인
const dateInfo = $('날짜 계산').first().json;
const sheetResp = $('Sheets 전일 행 조회').first().json || {};

// Sheets: C=makeshop, D=naver, E=st11, F=crm, G=coupang, H=rocket, I=기타, J=일 합계
let row = [];
try {
  const values = sheetResp.values || [[]];
  row = values[0] || [];
} catch(e) {}

// 파싱 유틸
const num = (v) => {
  if (v === undefined || v === null || v === '') return 0;
  const s = String(v).replace(/[^0-9.-]/g, '');
  return parseInt(s) || 0;
};

const ms = num(row[0]);       // C
const nv = num(row[1]);       // D
const st = num(row[2]);       // E
const crm = num(row[3]);      // F
const coupang = num(row[4]);  // G (수동)
const rocket = num(row[5]);   // H (수동)
const etc = num(row[6]);      // I (수동)
const sheetTotal = num(row[7]); // J

// 수동 채널 입력 여부 (하나라도 있으면 ok)
// 단, 0으로 명시 입력한 경우를 판별 어려우므로, 빈 셀만 미입력으로 간주
const manualEntered = (row.length >= 7) && (row[4] !== '' || row[5] !== '' || row[6] !== '');

return [{ json: {
  sheetRow: row,
  makeshop: ms,
  naver: nv,
  st11: st,
  crm: crm,
  coupang: coupang,
  rocket: rocket,
  etc: etc,
  sheetTotal,
  manualEntered,
  dateInfo,
} }];

// 리포트 집계: 올해/작년 NocoDB 데이터 + 전일 채널 데이터
// 중복 방어: 같은 report_date의 레코드가 여러 개면 가장 큰 Id만 사용
const parsed = $('Sheet 행 파싱').first().json;
const di = parsed.dateInfo;

const cyResp = $('올해 NocoDB 조회').first().json || {};
const pyResp = $('작년 NocoDB 조회').first().json || {};
const cyList = cyResp.list || [];
const pyList = pyResp.list || [];

// 중복 제거: date별로 가장 큰 Id만
const dedupe = (list) => {
  const map = {};
  for (const r of list) {
    const d = r.report_date;
    if (!d) continue;
    if (!map[d] || r.Id > map[d].Id) map[d] = r;
  }
  return map;
};
const cyMap = dedupe(cyList);
const pyMap = dedupe(pyList);

// 올해 누계 (1/1 ~ 어제)
let ytdRev = 0, ytdOrd = 0;
for (const d in cyMap) {
  if (d <= di.yDate) {
    ytdRev += parseInt(cyMap[d].total_revenue || 0);
    ytdOrd += parseInt(cyMap[d].total_orders || 0);
  }
}

// 이번 달 누계 (이번달 1일 ~ 어제)
let mtdRev = 0, mtdOrd = 0;
const mtdDaily = []; // 월 일별
for (const d in cyMap) {
  if (d.startsWith(di.yMonth) && d <= di.yDate) {
    const rev = parseInt(cyMap[d].total_revenue || 0);
    mtdRev += rev;
    mtdOrd += parseInt(cyMap[d].total_orders || 0);
    mtdDaily.push({ date: d, rev });
  }
}
mtdDaily.sort((a, b) => a.date.localeCompare(b.date));

// 작년 동기간 누계 (전년 1/1 ~ 전년 같은 달 같은 날)
let pytdRev = 0;
const prevSameDay = di.prevYear + di.yDate.slice(4); // 2025-04-09
for (const d in pyMap) {
  if (d <= prevSameDay) {
    pytdRev += parseInt(pyMap[d].total_revenue || 0);
  }
}

// 작년 동월 누계 (전년 같은 달 1일 ~ 같은 날)
let prevMtdRev = 0;
for (const d in pyMap) {
  if (d.startsWith(di.prevYearMonth) && d <= prevSameDay) {
    prevMtdRev += parseInt(pyMap[d].total_revenue || 0);
  }
}

// 작년 전체 & 작년 같은 달 전체
let prevYearTotal = 0, prevMonthTotal = 0;
for (const d in pyMap) {
  const rev = parseInt(pyMap[d].total_revenue || 0);
  prevYearTotal += rev;
  if (d.startsWith(di.prevYearMonth)) prevMonthTotal += rev;
}

// 전일 채널 데이터 (Sheets 기준, 수동이 있으면 그 값 사용)
const yesterdayTotal = parsed.makeshop + parsed.naver + parsed.st11 + parsed.crm + parsed.coupang + parsed.rocket + parsed.etc;
const yesterdayOrdersEst = (cyMap[di.yDate] && parseInt(cyMap[di.yDate].total_orders || 0)) || 0;

// ─── 리포트 생성 ───
const fmt = (n) => Math.round(n).toLocaleString('ko-KR');
const pct = (part, whole) => whole > 0 ? Math.round(part / whole * 100) : 0;
const yoy = (cur, prev) => {
  if (!prev || prev === 0) return '-';
  const diff = (cur - prev) / prev * 100;
  const sign = diff >= 0 ? '+' : '';
  return sign + diff.toFixed(1) + '%';
};

let msg = `<b>💰 통합 일일 매출 — ${di.label}</b>\n`;
msg += '━━━━━━━━━━━━━━━━━━━\n';

// ── 전일 매출 ──
if (yesterdayTotal === 0 && !parsed.manualEntered) {
  msg += `⚠️ 전일 자동 채널 데이터 없음 또는 수집 실패\n`;
  msg += `⚠️ 수동 채널도 미입력 (쿠팡/로켓/기타)\n\n`;
} else {
  msg += `📊 <b>전일 총 매출: ${fmt(yesterdayTotal)}원</b>`;
  if (yesterdayOrdersEst > 0) msg += ` (${yesterdayOrdersEst}건)`;
  msg += '\n\n';
  msg += '<b>채널별:</b>\n';
  msg += `🏪 메이크샵   ${fmt(parsed.makeshop)}원 (${pct(parsed.makeshop, yesterdayTotal)}%)\n`;
  msg += `🟢 네이버     ${fmt(parsed.naver)}원 (${pct(parsed.naver, yesterdayTotal)}%)\n`;
  msg += `🔴 11번가     ${fmt(parsed.st11)}원 (${pct(parsed.st11, yesterdayTotal)}%)\n`;
  msg += `📞 직접거래   ${fmt(parsed.crm)}원 (${pct(parsed.crm, yesterdayTotal)}%)\n`;
  if (parsed.manualEntered) {
    msg += `📦 쿠팡윙     ${fmt(parsed.coupang)}원 (${pct(parsed.coupang, yesterdayTotal)}%) [수동]\n`;
    msg += `🚀 로켓배송   ${fmt(parsed.rocket)}원 (${pct(parsed.rocket, yesterdayTotal)}%) [수동]\n`;
    if (parsed.etc > 0) msg += `⚪ 기타       ${fmt(parsed.etc)}원 [수동]\n`;
  } else {
    msg += `⏳ 쿠팡윙/로켓/기타 — 수동 입력 대기\n`;
  }
  msg += '\n';
}

// ── 이번 달 누계 ──
msg += '━━━━━━━━━━━━━━━━━━━\n';
msg += `📅 <b>이번 달 (${di.monthNum}/1~${di.monthNum}/${di.dayNum}, ${di.mtdDays}일)</b>\n`;
msg += `   누계: ${fmt(mtdRev)}원\n`;
if (di.mtdDays > 0) msg += `   일평균: ${fmt(mtdRev / di.mtdDays)}원\n`;
msg += `   전년 동기: ${fmt(prevMtdRev)}원 (${yoy(mtdRev, prevMtdRev)})\n`;
msg += `   전년 ${di.monthNum}월 전체: ${fmt(prevMonthTotal)}원\n\n`;

// ── 올해 누계 ──
msg += '━━━━━━━━━━━━━━━━━━━\n';
msg += `📆 <b>올해 누계 (1/1 ~ ${di.monthNum}/${di.dayNum})</b>\n`;
msg += `   누계: ${fmt(ytdRev)}원\n`;
msg += `   전년 동기: ${fmt(pytdRev)}원 (${yoy(ytdRev, pytdRev)})\n`;
msg += `   전년 전체: ${fmt(prevYearTotal)}원\n\n`;

// ── 이번 달 일별 미니차트 (막대 대신 숫자) ──
if (mtdDaily.length > 0) {
  msg += '━━━━━━━━━━━━━━━━━━━\n';
  msg += `📈 <b>${di.monthNum}월 일별</b>\n`;
  const maxRev = Math.max(...mtdDaily.map(d => d.rev));
  for (const { date, rev } of mtdDaily) {
    const day = parseInt(date.slice(8, 10));
    const barLen = maxRev > 0 ? Math.round(rev / maxRev * 10) : 0;
    const bar = '█'.repeat(barLen) + '▁'.repeat(10 - barLen);
    msg += `${String(day).padStart(2, ' ')}일 ${bar} ${fmt(rev)}\n`;
  }
}

return [{ json: {
  chatId: di.chatId,
  message: msg,
  yDate: di.yDate,
  mtdRev,
  ytdRev,
  prevMtdRev,
  pytdRev,
  manualEntered: parsed.manualEntered,
  parsed,
} }];
